import React from "react";

import {
  BrowserRouter,
  Routes,
  Route
} from "react-router-dom";

import Sidebar from "./components/Sidebar";

import ChatBox from "./components/ChatBox";
import BudgetCard from "./components/BudgetCard";
import SafetyCard from "./components/SafetyCard";
import Recommendations from "./components/Recommendations";
import Itinerary from "./components/Itinerary";

function RoutesPage() {

  return (
    <div className="page">
      <h1>Routes Information</h1>
    </div>
  );
}

function HotelsPage() {

  return (
    <div className="page">
      <h1>Hotels Information</h1>
    </div>
  );
}

function App() {

  return (

    <BrowserRouter>

      <div style={{ display: "flex" }}>

        <Sidebar />

        <div
          style={{
            marginLeft: "280px",
            width: "100%",
            padding: "30px"
          }}
        >

          <Routes>

            <Route
              path="/"
              element={<ChatBox />}
            />

            <Route
              path="/destinations"
              element={<Recommendations />}
            />

            <Route
              path="/budget"
              element={<BudgetCard />}
            />

            <Route
              path="/safety"
              element={<SafetyCard />}
            />

            <Route
              path="/routes"
              element={<RoutesPage />}
            />

            <Route
              path="/hotels"
              element={<HotelsPage />}
            />

            <Route
              path="/itinerary"
              element={<Itinerary />}
            />

          </Routes>

        </div>

      </div>

    </BrowserRouter>
  );
}

export default App;
